import React, { useState } from 'react';
import api from '../api/axiosConfig';
import ReactMarkdown from 'react-markdown';
import { Terminal, Cpu, Download, ShieldCheck, Zap } from 'lucide-react';
import toast from 'react-hot-toast';

const INPUT_BG = '#111318';

const GeneratePage = () => {
  const [query, setQuery]     = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult]   = useState(null);
  const [visible, setVisible] = useState(false); // simple CSS fade instead of framer-motion

  const handleGenerate = async (e) => {
    e.preventDefault();
    if (!query.trim()) return;
    setLoading(true);
    setResult(null);
    setVisible(false);
    try {
      const response = await api.post('/portfolio/generate', { query });
      setResult(response.data.data);
      requestAnimationFrame(() => setVisible(true)); // trigger fade-in after mount
      toast.success('STRATEGY_SYNTHESIS_COMPLETE');
    } catch (err) {
      console.error('Synthesis Node Failure:', err);
      toast.error('SYSTEM_FAILURE: AGENTIC_DEBATE_INTERRUPTED');
    } finally {
      setLoading(false);
    }
  };

  const handleDownloadPDF = async () => {
    try {
      const response = await api.post('/portfolio/export', result, { responseType: 'blob' });
      const url  = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href  = url;
      link.setAttribute('download', `Finify_Strategy_${Date.now()}.pdf`);
      document.body.appendChild(link);
      link.click();
      link.remove();
    } catch {
      toast.error('PDF_EXPORT_FAILED');
    }
  };

  return (
    <div
      className="reveal-node"
      style={{
        flex: 1,
        width: '100%',
        maxWidth: '1000px',
        margin: '0 auto',
        padding: '2.5rem 1.5rem',
        boxSizing: 'border-box',
        display: 'flex',
        flexDirection: 'column',
        gap: '2rem',
      }}
    >
      {/* ── Header ── */}
      <div style={{
        paddingBottom: '1.5rem',
        borderBottom: '1px solid var(--surface-border)',
      }}>
        <h1 style={{
          display: 'flex',
          alignItems: 'center',
          gap: '0.75rem',
          fontSize: '1.4rem',
          fontWeight: 800,
          letterSpacing: '-0.02em',
          textTransform: 'uppercase',
          color: 'var(--text-primary)',
          margin: '0 0 0.4rem',
        }}>
          <Cpu size={22} color="var(--accent-primary)" />
          Strategy_Engine_<span style={{ color: 'var(--accent-primary)' }}>v3.2</span>
        </h1>
        <p style={{
          fontSize: '0.58rem',
          color: 'var(--text-muted)',
          textTransform: 'uppercase',
          letterSpacing: '0.28em',
          margin: 0,
        }}>
          Active Node: Agentic_RAG_Cluster // Corpus: NSE_BSE_2026
        </p>
      </div>

      {/* ── Input ── */}
      <form onSubmit={handleGenerate} style={{ position: 'relative' }}>
        <input
          placeholder="DESCRIBE_GOAL: e.g., Aggressive growth in Indian EV sector for 3 years..."
          value={query}
          onChange={e => setQuery(e.target.value)}
          disabled={loading}
          style={{
            width: '100%',
            boxSizing: 'border-box',
            padding: '1.25rem 10rem 1.25rem 1.25rem',
            borderRadius: '14px',
            border: '1px solid var(--input-border)',
            background: 'var(--input-bg)',
            color: 'var(--text-primary)',
            fontFamily: 'monospace',
            fontSize: '0.8rem',
            outline: 'none',
            transition: 'border-color 0.25s ease, box-shadow 0.25s ease',
            WebkitBoxShadow: `0 0 0px 1000px ${INPUT_BG} inset`,
            WebkitTextFillColor: 'var(--text-primary)',
            caretColor: 'var(--accent-primary)',
          }}
          onFocus={e => {
            e.target.style.borderColor = 'var(--accent-primary)';
            e.target.style.boxShadow   = '0 0 14px var(--accent-glow)';
          }}
          onBlur={e => {
            e.target.style.borderColor = 'var(--input-border)';
            e.target.style.boxShadow   = 'none';
          }}
        />
        <button
          type="submit"
          disabled={loading || !query.trim()}
          className="cyber-btn"
          style={{
            position: 'absolute',
            right: '0.6rem',
            top: '50%',
            transform: 'translateY(-50%)',
            width: 'auto',
            padding: '0.55rem 1.25rem',
            fontSize: '0.6rem',
            whiteSpace: 'nowrap',
          }}
        >
          {loading ? 'PROCESSING...' : 'INITIALIZE'}
        </button>
      </form>

      {/* ── Loading ── */}
      {loading && (
        <div style={{
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
          padding: '5rem 0',
          gap: '1.25rem',
        }}>
          <div style={{ position: 'relative', width: '56px', height: '56px' }}>
            <div style={{
              width: '56px', height: '56px',
              border: '2px solid var(--surface-border)',
              borderTopColor: 'var(--accent-primary)',
              borderRadius: '50%',
              animation: 'genSpin 0.9s linear infinite',
            }} />
            <Zap
              size={18}
              color="var(--accent-primary)"
              style={{
                position: 'absolute',
                top: '50%', left: '50%',
                transform: 'translate(-50%, -50%)',
                animation: 'genPulse 1s ease-in-out infinite',
              }}
            />
          </div>
          <div style={{ textAlign: 'center' }}>
            <p style={{
              fontSize: '0.6rem',
              fontWeight: 700,
              textTransform: 'uppercase',
              letterSpacing: '0.4em',
              color: 'var(--accent-primary)',
              margin: '0 0 0.4rem',
              animation: 'genPulse 1.5s ease-in-out infinite',
            }}>
              Agentic_Debate_In_Progress
            </p>
            <p style={{
              fontSize: '0.55rem',
              fontFamily: 'monospace',
              color: 'var(--text-muted)',
              margin: 0,
            }}>
              CROSS_REFERENCING_STOCKS_JSON + YFINANCE_LIVE_DATA
            </p>
          </div>
        </div>
      )}

      {/* ── Result ── */}
      {result && !loading && (
        <div style={{
          display: 'flex',
          flexDirection: 'column',
          gap: '1rem',
          opacity: visible ? 1 : 0,
          transform: visible ? 'translateY(0)' : 'translateY(16px)',
          transition: 'opacity 0.5s ease, transform 0.5s ease',
        }}>
          {/* Toolbar */}
          <div style={{
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'center',
            padding: '0.85rem 1.1rem',
            borderRadius: '14px',
            background: 'var(--accent-muted)',
            border: '1px solid var(--accent-primary)',
            flexWrap: 'wrap',
            gap: '0.75rem',
          }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.6rem' }}>
              <ShieldCheck size={16} color="var(--accent-primary)" />
              <span style={{
                fontSize: '0.6rem',
                fontWeight: 700,
                textTransform: 'uppercase',
                letterSpacing: '0.18em',
                color: 'var(--accent-primary)',
              }}>
                Strategy_Verified_By_Risk_Agent
              </span>
            </div>
            <button
              onClick={handleDownloadPDF}
              style={{
                display: 'flex',
                alignItems: 'center',
                gap: '0.5rem',
                fontSize: '0.6rem',
                fontWeight: 700,
                textTransform: 'uppercase',
                letterSpacing: '0.15em',
                color: 'var(--accent-primary)',
                background: 'transparent',
                border: '1px solid var(--accent-primary)',
                borderRadius: '8px',
                padding: '0.4rem 0.9rem',
                cursor: 'pointer',
                transition: 'all 0.25s ease',
              }}
              onMouseEnter={e => {
                e.currentTarget.style.background = 'var(--accent-primary)';
                e.currentTarget.style.color      = '#000';
              }}
              onMouseLeave={e => {
                e.currentTarget.style.background = 'transparent';
                e.currentTarget.style.color      = 'var(--accent-primary)';
              }}
            >
              <Download size={13} /> Export_Report
            </button>
          </div>

          {/* Content grid */}
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(3, 1fr)',
            gap: '1rem',
          }}>
            <ResultBlock title="01_Executive_Summary" style={{ gridColumn: '1 / -1' }}>
              <p style={{
                color: 'var(--text-secondary)',
                fontSize: '0.85rem',
                lineHeight: 1.7,
                fontStyle: 'italic',
                margin: 0,
                paddingLeft: '1rem',
                borderLeft: '2px solid var(--accent-primary)',
              }}>
                {result.summary}
              </p>
            </ResultBlock>

            <ResultBlock title="02_Allocations" style={{ gridColumn: 'span 1' }}>
              <MarkdownContent>{result.holdings}</MarkdownContent>
            </ResultBlock>

            <ResultBlock title="03_Strategic_Rationale" style={{ gridColumn: 'span 2' }}>
              <MarkdownContent>{result.rationale}</MarkdownContent>
            </ResultBlock>
          </div>
        </div>
      )}

      <style>{`
        @keyframes genSpin  { to { transform: rotate(360deg); } }
        @keyframes genPulse { 0%,100% { opacity:1; } 50% { opacity:0.4; } }
      `}</style>
    </div>
  );
};

const ResultBlock = ({ title, children, style = {} }) => (
  <div style={{
    padding: '1.5rem',
    borderRadius: '18px',
    background: 'var(--surface-glass)',
    border: '1px solid var(--surface-border)',
    backdropFilter: 'blur(12px)',
    WebkitBackdropFilter: 'blur(12px)',
    ...style,
  }}>
    <h3 style={{
      display: 'flex',
      alignItems: 'center',
      gap: '0.5rem',
      fontSize: '0.6rem',
      fontWeight: 700,
      textTransform: 'uppercase',
      letterSpacing: '0.2em',
      color: 'var(--accent-primary)',
      margin: '0 0 1rem',
    }}>
      <Terminal size={12} color="var(--accent-primary)" />
      {title}
    </h3>
    {children}
  </div>
);

const MarkdownContent = ({ children }) => (
  <div style={{ fontSize: '0.82rem', lineHeight: 1.7, color: 'var(--text-secondary)' }}>
    <style>{`
      .md-content p      { margin: 0 0 0.6rem; color: var(--text-secondary); }
      .md-content ul     { padding-left: 1.25rem; margin: 0 0 0.6rem; }
      .md-content li     { margin-bottom: 0.3rem; color: var(--text-secondary); }
      .md-content strong { color: var(--accent-primary); font-weight: 700; }
      .md-content h1,.md-content h2,.md-content h3 {
        color: var(--text-primary); font-weight: 700;
        margin: 0.75rem 0 0.4rem; font-size: 0.88rem;
      }
    `}</style>
    <div className="md-content">
      <ReactMarkdown>{children}</ReactMarkdown>
    </div>
  </div>
);

export default GeneratePage;
